namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Name { get; set; }
    public string? Description { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public required string Name { get; set; }
    public required string Title { get; set; }
    public string? Bio { get; set; }
    public string? Email { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public string? Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public int DepartmentId { get; set; }
    public required Department Department { get; set; }
    public int InstructorId { get; set; }
    public required Instructor Instructor { get; set; }
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string? FullName { get; set; }

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string? StudentId { get; set; }

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    Task<List<Department>> GetDepartmentsAsync();
    Task<Department?> GetDepartmentAsync(int id);
    Task<List<Course>> GetCoursesAsync(string? searchTerm = null, int? departmentId = null);
    Task<List<Course>> GetFeaturedCoursesAsync();
    Task<Course?> GetCourseAsync(int id);
    Task<bool> SubmitEnrollmentRequestAsync(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments =
        [
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." },
        ];

        _instructors =
        [
            new() { Id = 1, Name = "Dr. Ada Lovelace", Title = "Professor", Bio = "Pioneer in computing theory with 20 years of teaching experience. Research interests include algorithm design and computational complexity.", Email = "alovelace@university.edu" },
            new() { Id = 2, Name = "Dr. Alan Turing", Title = "Associate Professor", Bio = "Specialist in artificial intelligence and machine learning. Published over 50 papers on computational theory.", Email = "aturing@university.edu" },
            new() { Id = 3, Name = "Dr. Emmy Noether", Title = "Professor", Bio = "Expert in abstract algebra and theoretical physics. Recipient of the Distinguished Teaching Award.", Email = "enoether@university.edu" },
            new() { Id = 4, Name = "Dr. William Shakespeare", Title = "Professor", Bio = "Renowned scholar of English literature and creative writing. Author of several critically acclaimed textbooks.", Email = "wshakespeare@university.edu" },
            new() { Id = 5, Name = "Dr. Marie Curie", Title = "Professor", Bio = "Leading researcher in experimental physics and radiation studies. Two-time recipient of the Faculty Excellence Award.", Email = "mcurie@university.edu" },
            new() { Id = 6, Name = "Dr. Herodotus", Title = "Associate Professor", Bio = "Specialist in ancient civilizations and historiography. Leads the university's archaeological research program.", Email = "herodotus@university.edu" },
        ];

        _courses =
        [
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of how computers work. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, Department = _departments[0], InstructorId = 1, Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Includes weekly programming assignments in Java.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, Department = _departments[0], InstructorId = 2, Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Principles of relational database design, SQL, normalization, indexing, and transaction management. Students build a complete database-backed application as a semester project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, Department = _departments[0], InstructorId = 1, Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 4, Code = "CS 450", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search algorithms, knowledge representation, machine learning fundamentals, natural language processing, and neural networks.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 1, Department = _departments[0], InstructorId = 2, Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics. Graphing calculator required.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, Department = _departments[1], InstructorId = 3, Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications. Essential for students in science, engineering, and data science.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 2, Department = _departments[1], InstructorId = 3, Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 7, Code = "MATH 305", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis with real-world data sets.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 2, Department = _departments[1], InstructorId = 3, Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 8, Code = "ENG 101", Title = "College Composition", Description = "Develop effective academic writing skills through essay assignments, peer review workshops, and revision strategies. Emphasis on argumentation, evidence, and clarity.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, Department = _departments[2], InstructorId = 4, Instructor = _instructors[3], IsFeatured = false },
            new() { Id = 9, Code = "ENG 220", Title = "World Literature", Description = "A global survey of literary masterworks from antiquity to the modern era. Readings include works from Asia, Africa, Europe, and the Americas.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", DepartmentId = 3, Department = _departments[2], InstructorId = 4, Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes a weekly lab session. Calculus I is a co-requisite.", Credits = 4, Schedule = "Tue/Thu 8:00–9:20 AM, Lab: Fri 2:00–4:50 PM", DepartmentId = 4, Department = _departments[3], InstructorId = 5, Instructor = _instructors[4], IsFeatured = false },
            new() { Id = 11, Code = "PHYS 201", Title = "Modern Physics", Description = "Special relativity, quantum mechanics, atomic and nuclear physics. Explores the revolutionary ideas that reshaped our understanding of the universe.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 4, Department = _departments[3], InstructorId = 5, Instructor = _instructors[4], IsFeatured = true },
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 5, Department = _departments[4], InstructorId = 6, Instructor = _instructors[5], IsFeatured = false },
            new() { Id = 13, Code = "HIST 250", Title = "The Age of Revolutions", Description = "Examines political, industrial, and intellectual revolutions from the 18th to 19th centuries that shaped the modern world.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", DepartmentId = 5, Department = _departments[4], InstructorId = 6, Instructor = _instructors[5], IsFeatured = false },
        ];
    }

    public Task<List<Department>> GetDepartmentsAsync()
        => Task.FromResult(_departments.ToList());

    public Task<Department?> GetDepartmentAsync(int id)
        => Task.FromResult(_departments.FirstOrDefault(d => d.Id == id));

    public Task<List<Course>> GetCoursesAsync(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                (c.Description?.Contains(term, StringComparison.OrdinalIgnoreCase) ?? false) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        return Task.FromResult(query.ToList());
    }

    public Task<List<Course>> GetFeaturedCoursesAsync()
        => Task.FromResult(_courses.Where(c => c.IsFeatured).ToList());

    public Task<Course?> GetCourseAsync(int id)
        => Task.FromResult(_courses.FirstOrDefault(c => c.Id == id));

    public Task<bool> SubmitEnrollmentRequestAsync(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return Task.FromResult(true);
    }
}

