@using UniversityCourseCatalog.Models

<div class="card h-100 shadow-sm">
    <div class="card-body d-flex flex-column">
        <div class="d-flex justify-content-between align-items-start mb-2">
            <span class="badge bg-primary">@Course.Department.Code</span>
            <span class="badge bg-secondary">@Course.Credits Credits</span>
        </div>
        <h5 class="card-title">@Course.Code</h5>
        <h6 class="card-subtitle mb-2 text-body-secondary">@Course.Title</h6>
        <p class="card-text flex-grow-1">@Truncate(Course.Description, 120)</p>
        <div class="d-flex justify-content-between align-items-center mt-auto">
            <small class="text-body-secondary">@Course.Instructor.Name</small>
            <a href="@($"/courses/{Course.Id}")" class="btn btn-outline-primary btn-sm">View Details</a>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required Course Course { get; set; }

    private static string Truncate(string? text, int maxLength)
    {
        if (string.IsNullOrEmpty(text) || text.Length <= maxLength)
            return text ?? "";
        return text[..maxLength] + "…";
    }
}

@using UniversityCourseCatalog.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title">@Instructor.Name</h5>
        <h6 class="card-subtitle mb-2 text-body-secondary">@Instructor.Title</h6>
        @if (!string.IsNullOrEmpty(Instructor.Bio))
        {
            <p class="card-text">@Instructor.Bio</p>
        }
        @if (!string.IsNullOrEmpty(Instructor.Email))
        {
            <a href="@($"mailto:{Instructor.Email}")" class="card-link">
                <i class="bi bi-envelope"></i> @Instructor.Email
            </a>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required Instructor Instructor { get; set; }
}

@using UniversityCourseCatalog.Models

<div class="mb-4">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in Courses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required List<Course> Courses { get; set; }
}

@using UniversityCourseCatalog.Models

<div class="mb-4">
    <h2 class="mb-3">Departments</h2>
    <div class="row row-cols-1 row-cols-md-3 row-cols-lg-5 g-3">
        @foreach (var dept in Departments)
        {
            <div class="col">
