arguments.new_str:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">University Course Catalog</h1>
    <p class="lead text-body-secondary">Explore our departments and find the right courses for your academic journey.</p>
    <a href="/courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="/enroll" class="btn btn-outline-primary btn-lg">Enroll Now</a>
</div>

@if (_featuredCourses is not null && _departments is not null)
{
    <DepartmentLinks Departments="_departments" />
