@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Detail")</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="/courses" class="btn btn-outline-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@_course.Code — @_course.Title</h1>
            <span class="badge bg-primary me-2">@_course.Department.Name</span>
            <span class="badge bg-secondary">@_course.Credits Credits</span>

            <hr />

            <h4>Description</h4>
            <p>@_course.Description</p>

            <h4>Schedule</h4>
            <p><strong>@_course.Schedule</strong></p>

            <a href="/enroll" class="btn btn-primary mt-3">Enroll in This Course</a>
        </div>
        <div class="col-lg-4">
            <h4 class="mb-3">Instructor</h4>
            <InstructorBio Instructor="_course.Instructor" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? _course;

    protected override async Task OnInitializedAsync()
    {
        _course = await CatalogService.GetCourseAsync(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for the selected course has been received.</p>
        <hr />
        <a href="/courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                <DataAnnotationsValidator />
                <AntiforgeryToken />
                <ValidationSummary class="text-danger mb-3" />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="_model.FullName" />
                    <ValidationMessage For="() => _model.FullName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" placeholder="e.g., CS123456" @bind-Value="_model.StudentId" />
                    <ValidationMessage For="() => _model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @if (_courses is not null)
                        {
                            @foreach (var course in _courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title</option>
                            }
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private List<Course>? _courses;
    private bool _submitted;

    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    protected override async Task OnInitializedAsync()
    {
        _courses = await CatalogService.GetCoursesAsync();
    }

    private async Task HandleSubmit()
    {
        await CatalogService.SubmitEnrollmentRequestAsync(_model);
        _submitted = true;
    }
}

